import{_ as r,o,c as a,a3 as e}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"🔍 智能 OCR 快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/smart-ocr/index.md","filePath":"user-guide/tools/smart-ocr/index.md","lastUpdated":1778221347000}'),d={name:"user-guide/tools/smart-ocr/index.md"};function n(s,t,l,i,h,c){return o(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="🔍-智能-ocr-快速上手" tabindex="-1">🔍 智能 OCR 快速上手 <a class="header-anchor" href="#🔍-智能-ocr-快速上手" aria-label="Permalink to &quot;🔍 智能 OCR 快速上手&quot;">​</a></h1><p>在主页点击 <strong>智能 OCR</strong> 卡片进入工具。</p><blockquote><p><strong>一句话介绍</strong>：将图片中的文字&quot;提取&quot;出来，支持截图、扫描件、长图等多种场景。</p></blockquote><p>智能 OCR 工具支持 <strong>4 种识别引擎</strong>，并内置<strong>智能切图</strong>功能，能自动将长图按空白区域分割后再识别，大幅提升识别效率和准确率。</p><hr><h2 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td><strong>OCR 引擎</strong></td><td>负责文字识别的&quot;大脑&quot;，支持本地、云端等多种类型</td></tr><tr><td><strong>智能切图</strong></td><td>将长图自动分割成多个小块，逐个识别后再合并结果</td></tr><tr><td><strong>图片块 (Block)</strong></td><td>切图后产生的独立识别单元</td></tr><tr><td><strong>历史记录</strong></td><td>每次识别的结果会自动保存，方便回溯</td></tr></tbody></table><hr><h2 id="第一步-选择图片" tabindex="-1">第一步：选择图片 <a class="header-anchor" href="#第一步-选择图片" aria-label="Permalink to &quot;第一步：选择图片&quot;">​</a></h2><h3 id="支持格式" tabindex="-1">支持格式 <a class="header-anchor" href="#支持格式" aria-label="Permalink to &quot;支持格式&quot;">​</a></h3><ul><li>常见图片格式：PNG、JPG、JPEG、BMP、WebP</li><li>支持单张和批量上传</li></ul><h3 id="上传方式" tabindex="-1">上传方式 <a class="header-anchor" href="#上传方式" aria-label="Permalink to &quot;上传方式&quot;">​</a></h3><ol><li>点击预览区域的上传按钮</li><li>直接将图片文件拖拽到预览区域</li><li>支持多选文件，一次上传多张图片</li></ol><blockquote><p><strong>贴士</strong>：批量上传多张图片后，可以逐一选择处理，也可以一键批量识别全部。</p></blockquote><hr><h2 id="第二步-执行识别" tabindex="-1">第二步：执行识别 <a class="header-anchor" href="#第二步-执行识别" aria-label="Permalink to &quot;第二步：执行识别&quot;">​</a></h2><ol><li>在左侧<strong>控制面板</strong>中确认已选择好 OCR 引擎（默认为 Tesseract.js）</li><li>点击底部 <strong>&quot;识别当前图片&quot;</strong> 按钮（单张识别）或 <strong>&quot;批量识别全部&quot;</strong> 按钮（多张图片时显示）</li></ol><p>![识别按钮位置示意]（TODO: 截图 - 控制面板底部的识别按钮区域）</p><h3 id="识别过程中的状态反馈" tabindex="-1">识别过程中的状态反馈 <a class="header-anchor" href="#识别过程中的状态反馈" aria-label="Permalink to &quot;识别过程中的状态反馈&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><code>pending</code></td><td>等待处理</td></tr><tr><td><code>processing</code></td><td>正在识别中</td></tr><tr><td><code>success</code></td><td>识别成功</td></tr><tr><td><code>error</code></td><td>识别失败（可点击重试）</td></tr></tbody></table><p>识别进度会实时在右侧结果面板中更新，每个图片块的状态一目了然。</p><hr><h2 id="第三步-查看结果" tabindex="-1">第三步：查看结果 <a class="header-anchor" href="#第三步-查看结果" aria-label="Permalink to &quot;第三步：查看结果&quot;">​</a></h2><p>识别完成后，右侧结果面板会展示每个图片块的识别文本：</p><h3 id="结果操作" tabindex="-1">结果操作 <a class="header-anchor" href="#结果操作" aria-label="Permalink to &quot;结果操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制文本</strong></td><td>一键复制识别结果到剪贴板</td></tr><tr><td><strong>编辑文本</strong></td><td>手动修正识别不准确的文字</td></tr><tr><td><strong>忽略/取消忽略</strong></td><td>标记不需要的块，复制时跳过</td></tr><tr><td><strong>重试单个块</strong></td><td>对识别失败的块重新识别</td></tr><tr><td><strong>重试所有失败</strong></td><td>一键重试所有失败块</td></tr></tbody></table><h3 id="结果导出" tabindex="-1">结果导出 <a class="header-anchor" href="#结果导出" aria-label="Permalink to &quot;结果导出&quot;">​</a></h3><p>识别后的文本支持复制粘贴到任意应用。未来版本计划加入更多导出格式。</p><hr><h2 id="第四步-管理历史记录" tabindex="-1">第四步：管理历史记录 <a class="header-anchor" href="#第四步-管理历史记录" aria-label="Permalink to &quot;第四步：管理历史记录&quot;">​</a></h2><p>每次成功的识别都会自动保存到历史记录中：</p><ol><li>点击控制面板顶部的 <strong>历史记录</strong> 按钮（📋 图标）</li><li>在历史记录对话框中可以： <ul><li><strong>加载历史</strong>：查看之前识别的完整结果</li><li><strong>重新识别</strong>：用当前引擎配置重新识别历史图片</li></ul></li></ol><p>![历史记录对话框]（TODO: 截图 - 历史记录弹窗）</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：识别出的文字乱七八糟怎么办？</strong> A：检查是否选对了引擎和语言。中文图片请选择&quot;简体中文+英文&quot;，遇到复杂排版可以尝试切换 VLM 引擎。</p><p><strong>Q：长图识别结果不理想？</strong> A：确保智能切图功能已启用，并适当调整切图参数（见进阶配置）。</p><p><strong>Q：识别速度太慢？</strong> A：可以增加 Tesseract 引擎的并发数，或切换到 Native OCR 引擎（速度最快）。</p><hr><blockquote><p>💡 <strong>下一步</strong>：想了解各引擎的区别和高级调优？请阅读 <a href="./advanced">进阶配置</a>。</p></blockquote>',40)])])}const b=r(d,[["render",n]]);export{g as __pageData,b as default};
